import React from 'react';
import { Menu } from 'antd';
import { MenuItem } from '../../Layout/app/Types';
import { menuData } from './MenuItemsData';

const { SubMenu } = Menu;

const generateMenuItems = (items: MenuItem[]): React.ReactNode => {
  return items.map((item) => {
    if (item.children) {
      // Divide the children into two arrays
      const splitIndex = Math.ceil(item.children.length / 2);
      const firstHalf = item.children.slice(0, splitIndex);
      const secondHalf = item.children.slice(splitIndex);

      return (
        <SubMenu key={item.key} icon={item.icon} title={item.label}>
          <div className="mega-menu">
            <div className="mega-menu-column">
              {generateMenuItems(firstHalf)}
            </div>
            <div className="mega-menu-column">
              {generateMenuItems(secondHalf)}
            </div>
          </div>
        </SubMenu>
      );
    } else {
      return (
        <Menu.Item key={item.key}>
          <a href={`/${item.key}`}>{item.label}</a>
        </Menu.Item>
      );
    }
  });
};

const MenuItems: React.FC<{ items: MenuItem[] }> = ({ items }) => {
  return <Menu mode="horizontal">{generateMenuItems(items)}</Menu>;
};

const App = () => {
  return <MenuItems items={menuData} />;
};

export default App;
